def {{nama_fungsi}}(template_text, **variables):
    """Isi placeholder $nama_variabel pada template_text dengan nilai dari variables.
    Melempar error jelas jika ada placeholder yang belum diisi."""
    tpl = string.Template(template_text)
    try:
        return tpl.substitute(**variables)
    except KeyError as e:
        raise ValueError(f"Placeholder belum diisi: {e}")

def {{nama_fungsi}}(system_prompt=None, history=None, user_message=None):
    """Bangun list pesan role-based. history: list of (role, content) opsional."""
    messages = []
    if system_prompt:
        messages.append({"role": "system", "content": system_prompt})
    if history:
        for role, content in history:
            messages.append({"role": role, "content": content})
    if user_message:
        messages.append({"role": "user", "content": user_message})
    return messages
